// show/hide ArrivalTime and FlightNumber fields and make them mandatory when PickUp field is enabled
function toggleArrivalInfo() {
    var pickUpRequired = fd.field('PickUp').value
    
    if(pickUpRequired) {
        fd.field('ArrivalTime').required = true;
        fd.field('FlightNumber').required = true;
        
        fd.field('ArrivalTime').hidden = false
        fd.field('FlightNumber').hidden = false;
    }
    else {
        fd.field('ArrivalTime').required = false;
        fd.field('FlightNumber').required = false;
        
        fd.field('ArrivalTime').hidden = true;
        fd.field('FlightNumber').hidden = true;
    }
}

fd.rendered(function () {

    // call the function on form load
    toggleArrivalInfo();
    
    // call the function when the PickUp field changes
    fd.field('PickUp').$on('change', toggleArrivalInfo);
});

